  StepperContent,
} from "@/registry/new-york-v4/ui/stepper"

export default function StepperDemo() {
  const [activeStep, setActiveStep] = React.useState(1)

  return (
    <div className="flex w-full max-w-xl flex-col gap-8">
      {/* Horizontal stepper */}
      <Stepper
        orientation="horizontal"
        activeStep={activeStep}
        onStepChange={setActiveStep}
      >
        <StepperItem step={1}>
          <StepperTrigger aria-label="Go to step 1" />
          <StepperTitle>Account</StepperTitle>
        </StepperItem>
        <StepperSeparator afterStep={1} />
        <StepperItem step={2}>
          <StepperTrigger aria-label="Go to step 2" />
          <StepperTitle>Profile</StepperTitle>
        </StepperItem>
        <StepperSeparator afterStep={2} />
        <StepperItem step={3}>
          <StepperTrigger aria-label="Go to step 3" />
          <StepperTitle>Review</StepperTitle>
        </StepperItem>
      </Stepper>

      {/* Navigation buttons */}
      <div className="flex items-center gap-2">
        <button
          type="button"
          disabled={activeStep === 1}
          onClick={() => setActiveStep((s) => Math.max(1, s - 1))}
