          type="button"
          disabled={activeStep === 3}
          onClick={() => setActiveStep((s) => Math.min(3, s + 1))}
          className="rounded-md border px-4 py-2 text-sm disabled:opacity-50"
        >
          Next
        </button>
      </div>
    </div>
  )
