}
```

### 3e. `StepperDescription` (`data-slot="stepper-description"`)

```typescript
function StepperDescription({ className, ...props }: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-description"
      className={cn("text-xs text-muted-foreground", className)}
