"use client"

import * as React from "react"
import { CheckIcon } from "lucide-react"

import { cn } from "@/lib/utils"

// ── Types ──────────────────────────────────────────────────────────────────

type StepperOrientation = "horizontal" | "vertical"
type StepState = "active" | "completed" | "inactive"

type StepperContextValue = {
  orientation: StepperOrientation
  activeStep: number
  onStepChange?: (step: number) => void
}

type StepperItemContextValue = {
  step: number
  state: StepState
  disabled: boolean
}

// ── Contexts ───────────────────────────────────────────────────────────────

const StepperContext = React.createContext<StepperContextValue | null>(null)
const StepperItemContext = React.createContext<StepperItemContextValue | null>(null)

// ── Hooks ──────────────────────────────────────────────────────────────────

function useStepper(): StepperContextValue {
  const context = React.useContext(StepperContext)
  if (!context) {
    throw new Error("useStepper must be used within a <Stepper />")
  }
  return context
}

function useStepperItem(): StepperItemContextValue {
  const context = React.useContext(StepperItemContext)
  if (!context) {
    throw new Error("useStepperItem must be used within a <StepperItem />")
  }
  return context
}

// ── Stepper (root) ─────────────────────────────────────────────────────────

type StepperProps = React.ComponentProps<"div"> & {
  orientation?: StepperOrientation
  activeStep?: number
  defaultStep?: number
  onStepChange?: (step: number) => void
}

function Stepper({
  className,
  orientation = "horizontal",
  activeStep: activeStepProp,
  defaultStep = 1,
  onStepChange,
  children,
  ...props
}: StepperProps) {
  const [_activeStep, _setActiveStep] = React.useState(defaultStep)
  const activeStep = activeStepProp ?? _activeStep

  const handleStepChange = React.useCallback(
    (step: number) => {
      if (onStepChange) {
        onStepChange(step)
      } else {
        _setActiveStep(step)
      }
    },
    [onStepChange]
  )

  return (
    <StepperContext.Provider
      value={{ orientation, activeStep, onStepChange: handleStepChange }}
    >
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn(
          "group/stepper flex",
          "data-[orientation=horizontal]:flex-row data-[orientation=horizontal]:items-start",
          "data-[orientation=vertical]:flex-col data-[orientation=vertical]:items-start",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperContext.Provider>
  )
}

// ── StepperItem ────────────────────────────────────────────────────────────

type StepperItemProps = React.ComponentProps<"div"> & {
  step: number
  disabled?: boolean
}

function StepperItem({
  className,
  step,
  disabled = false,
  children,
  ...props
}: StepperItemProps) {
  const { activeStep } = useStepper()

  const state: StepState =
    step === activeStep ? "active"
    : step < activeStep ? "completed"
    : "inactive"

  return (
    <StepperItemContext.Provider value={{ step, state, disabled }}>
      <div
        data-slot="stepper-item"
        data-state={state}
        data-disabled={disabled ? "" : undefined}
        className={cn(
          "group/stepper-item flex shrink-0",
          "group-data-[orientation=horizontal]/stepper:flex-col group-data-[orientation=horizontal]/stepper:items-center group-data-[orientation=horizontal]/stepper:flex-1",
          "group-data-[orientation=vertical]/stepper:flex-row group-data-[orientation=vertical]/stepper:items-start group-data-[orientation=vertical]/stepper:gap-4",
          "data-[disabled]:pointer-events-none data-[disabled]:opacity-50",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperItemContext.Provider>
  )
}

// ── StepperTrigger ─────────────────────────────────────────────────────────

function StepperTrigger({
  className,
  children,
  ...props
}: React.ComponentProps<"button">) {
  const { onStepChange } = useStepper()
  const { step, state, disabled } = useStepperItem()

  return (
    <button
      data-slot="stepper-trigger"
      data-state={state}
      type="button"
      disabled={disabled}
      onClick={() => onStepChange?.(step)}
      className={cn(
        "inline-flex flex-col items-center gap-2 outline-none",
        "text-sm font-medium",
        "disabled:pointer-events-none disabled:opacity-50",
        "focus-visible:outline-none focus-visible:ring-[3px] focus-visible:ring-ring/50 rounded-sm",
        className
      )}
      {...props}
    >
      <span
        data-state={state}
        className={cn(
          "flex size-8 shrink-0 items-center justify-center rounded-full border-2 transition-all",
          "border-border bg-muted text-muted-foreground",
          "data-[state=active]:border-primary data-[state=active]:bg-primary data-[state=active]:text-primary-foreground",
          "data-[state=completed]:border-primary data-[state=completed]:bg-primary data-[state=completed]:text-primary-foreground"
        )}
      >
        {state === "completed" ? (
          <CheckIcon className="size-4" aria-hidden="true" />
        ) : (
          <span className="text-xs font-semibold">{step}</span>
        )}
      </span>
      {children}
    </button>
  )
}

// ── StepperTitle ───────────────────────────────────────────────────────────

function StepperTitle({ className, ...props }: React.ComponentProps<"p">) {
  const { state } = useStepperItem()

  return (
    <p
      data-slot="stepper-title"
      data-state={state}
      className={cn(
        "text-sm font-medium leading-none",
        "text-muted-foreground",
        "data-[state=active]:text-foreground",
        "data-[state=completed]:text-foreground",
        className
      )}
      {...props}
    />
  )
}

// ── StepperDescription ─────────────────────────────────────────────────────

function StepperDescription({
  className,
  ...props
}: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-description"
      className={cn("text-xs text-muted-foreground", className)}
      {...props}
    />
  )
}

// ── StepperSeparator ───────────────────────────────────────────────────────

type StepperSeparatorProps = React.ComponentProps<"div"> & {
  afterStep: number
}

function StepperSeparator({
  afterStep,
  className,
  ...props
}: StepperSeparatorProps) {
  const { activeStep } = useStepper()
  const isCompleted = afterStep < activeStep

  return (
    <div
      data-slot="stepper-separator"
      aria-hidden="true"
      className={cn(
        "shrink-0 bg-border transition-colors",
        isCompleted && "bg-primary",
        "group-data-[orientation=horizontal]/stepper:h-px group-data-[orientation=horizontal]/stepper:flex-1 group-data-[orientation=horizontal]/stepper:min-w-8 group-data-[orientation=horizontal]/stepper:self-center",
        "group-data-[orientation=vertical]/stepper:w-px group-data-[orientation=vertical]/stepper:min-h-8 group-data-[orientation=vertical]/stepper:ml-4 group-data-[orientation=vertical]/stepper:self-stretch",
        className
      )}
      {...props}
    />
  )
}

// ── StepperContent ─────────────────────────────────────────────────────────

function StepperContent({ className, ...props }: React.ComponentProps<"div">) {
  const { state } = useStepperItem()

  return (
    <div
      data-slot="stepper-content"
      data-state={state}
      hidden={state !== "active"}
      className={cn("hidden data-[state=active]:block", className)}
      {...props}
    />
  )
}

// ── Exports ────────────────────────────────────────────────────────────────

export {
  Stepper,
  StepperItem,
  StepperTrigger,
  StepperTitle,
  StepperDescription,
  StepperSeparator,
  StepperContent,
}

